    let mut m_odd: Option<i64> = None;
    let mut has_even = false;
    let mut has_odd = false;

    // Step 1: Analyze parity distribution and find M_odd (minimum odd number)
    for &x in nums1.iter() {
        if x % 2 == 0 {
            has_even = true;
        } else {
            has_odd = true;
            match m_odd {
                Some(m) => {
                    if x < m {
                        m_odd = Some(x);
                    }
                }
                None => {
                    m_odd = Some(x);
                }
            }
        }
    }

    // Case A: All Even numbers (has_odd = false)
    // Even Target is achievable (nums2 = nums1). Odd Target is not achievable.
    if !has_odd {
        return true;
    }

    // Case B: All Odd numbers (has_even = false)
    // Odd Target is achievable (nums2 = nums1). Even Target is not achievable.
    if !has_even {
        return true;
    }

    // Case C: Mixed Parity (has_odd = true and has_even = true)
    // Even Target is NOT achievable because the smallest odd number (m_odd) 
    // cannot be transformed into an even number > 0.
    // We must check if Odd Target is achievable.

    let m = m_odd.unwrap(); // m_odd must be Some(M) here

    // For Odd Target to be achievable, every even number E must satisfy E > M_odd.
